def solve(n: int) -> str:
    n_squared = n * n
    hex_part = format(n_squared, 'X')

    n_cubed = n * n * n
    base36_digits = []
    if n_cubed == 0:
        base36_part = '0'
    else:
        num = n_cubed
        while num > 0:
            remainder = num % 36
            if remainder < 10:
                base36_digits.append(str(remainder))
            else:
                base36_digits.append(chr(ord('A') + remainder - 10))
            num = num // 36
        base36_part = ''.join(reversed(base36_digits))

    return hex_part + base36_part
